/* Evidence: cmem-worked-cmem-realloc-transactional-growth-2 */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 9696; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


static int worked_cmem_realloc_transactional_growth_2(int **owner, size_t old_count, size_t new_count, int simulate_failure) {
  int *candidate;
  if (owner == NULL || *owner == NULL || new_count <= old_count || simulate_failure) return 0;
  candidate = (int *)realloc(*owner, new_count * sizeof **owner);
  if (candidate == NULL) return 0;
  *owner = candidate;
  (*owner)[new_count - 1] = 4;
  return 1;
}

int main(void) {
  int *owner = (int *)malloc(2 * sizeof *owner);
  int rejected;
  int accepted;
  int invariant;
  if (owner == NULL) return 2;
  owner[0] = 7;
  rejected = worked_cmem_realloc_transactional_growth_2(&owner, 2, 4, 1);
  accepted = worked_cmem_realloc_transactional_growth_2(&owner, 2, 4, 0);
  invariant = !rejected && accepted && owner[0] == 7 && owner[3] == 4;
  printf("realloc tail=%d invariant=%d\n", owner[3], invariant);
  free(owner);
  return invariant ? 0 : 1;
}

